  static void logHttpRequest(http.Request request) {
    log('HTTP Request: ${request.method} ${request.url}');
    log('Headers: ${request.headers}');
    if (request.body.isNotEmpty) {
      log('Body: ${request.body}');
    }
  }

  static void logHttpResponse(http.Response response) {
    log('HTTP Response: ${response.statusCode}');
    log('Headers: ${response.headers}');
    log('Body: ${response.body}');
  }

  static void logDatabaseOperation(String operation, String details) {
    log('Database Operation: $operation - Details: $details');
  }

  static void logAuthFlow(String action, String token) {
    log('Auth Flow: $action - Token: $token');
  }

  static void logUserInteraction(String interaction) {
    log('User Interaction: $interaction');
  }
}

